// AUTO-GENERATED — do not edit by hand.
// Elite Dangerous hand-authored named-sector regions (Coalsack/Pleiades/NGC/IC/M/Col
// nebula & cluster regions). Ported from the canonical EDTS `ha_regions`
// (Esvandiary/edts edtslib/pgdata.py — https://bitbucket.org/Esvandiary/edts/).
// Each region is one or more spheres (centre + radius, in galaxy light-years, Sol at
// the origin). Membership is first-match sphere containment; the list is pre-sorted
// SMALLEST-RADIUS-FIRST, reproducing ED's overlap priority (the most-specific region
// wins). Verified 100% region assignment against 557k named-sector systems with 0
// false positives on procedural space.

export interface IHASphere {
    /** Sphere centre X in galaxy light-years (Sol at origin). */
    cx: number;
    cy: number;
    cz: number;
    /** Sphere radius in light-years. */
    r: number;
}

export interface IHARegion {
    /** Canonically-cased hand-authored sector name, e.g. "Pleiades Sector". */
    name: string;
    spheres: IHASphere[];
    /** Whether the region sits behind a permit lock (Bleia, Col 70, Regor, …). */
    needsPermit: boolean;
}

