/**
 * Position-based lookup for Elite Dangerous hand-authored named sectors.
 *
 * The procedural name generator ({@link PGSectors.getSectorName}) only produces
 * the procedural sector name for a boxel. Systems that physically fall inside a
 * hand-authored nebula/cluster region are instead displayed by the game under
 * that region's name (with a suffix computed relative to the region's own
 * origin). This class answers "which hand-authored region, if any, contains
 * these galaxy coordinates?" so the decode path can override the procedural name.
 */
export class PGHASectors {
    /**
     * The hand-authored region whose sphere set contains the given galaxy
     * coordinates (in light-years, Sol at the origin), or `null` for procedural
     * space. {@link HA_REGIONS} is pre-sorted smallest-radius-first, so the first
     * containing region is the most-specific one — matching ED's overlap priority.
     */
    static regionForCoords(x: number, y: number, z: number): IHARegion | null {
        for (const region of HA_REGIONS) {
            for (const s of region.spheres) {
                const dx = x - s.cx;
                const dy = y - s.cy;
                const dz = z - s.cz;
                if (dx * dx + dy * dy + dz * dz <= s.r * s.r) {
                    return region;
                }
            }
        }
        return null;
    }
}
